{action_set_definitions}: {
  "get_initial_defect_metadata": {
    "description": "Retrieves the initial registered coordinates, machine_id, and reported morphology for a specific defect ID.",
    "parameters": {
      "type": "object",
      "properties": {
        "defect_id": {
          "type": "string",
          "description": "The unique identifier for the defect (e.g., 'FLW-SCAN-202')."
        }
      },
      "required": [
        "defect_id"
      ]
    },
    "example_output": {
      "initial_x": 550.02,
      "initial_y": 12.45,
      "reported_morphology": "Foreign Object Debris (FOD)",
      "associated_machine_id": "STN-550-ROBOT-A"
    }
  },
  "validate_spatial_mapping": {
    "description": "Checks synchronization status and retrieves the precise drift offset for the specified equipment and defect.",
    "parameters": {
      "type": "object",
      "properties": {
        "defect_id": {
          "type": "string",
          "description": "The unique identifier for the defect."
        },
        "machine_id": {
          "type": "string",
          "description": "The ID of the equipment to verify."
        }
      },
      "required": [
        "defect_id",
        "machine_id"
      ]
    },
    "example_output": {
      "sync_verified": true,
      "drift_offset_x": 0.005,
      "drift_offset_y": -0.002
    }
  },
  "calculate_offset_coordinates": {
    "description": "Applies a drift offset to base coordinates to determine exact corrected spatial mapping.",
    "parameters": {
      "type": "object",
      "properties": {
        "base_x": {
          "type": "number"
        },
        "base_y": {
          "type": "number"
        },
        "offset_x": {
          "type": "number"
        },
        "offset_y": {
          "type": "number"
        }
      },
      "required": [
        "base_x",
        "base_y",
        "offset_x",
        "offset_y"
      ]
    },
    "example_output": {
      "corrected_x": 550.025,
      "corrected_y": 12.448
    }
  },
  "get_telemetry_at_coordinates": {
    "description": "Performs a high-resolution diagnostic scan at specific X,Y coordinates to retrieve depth and morphological details.",
    "parameters": {
      "type": "object",
      "properties": {
        "machine_id": {
          "type": "string",
          "description": "The ID of the diagnostic equipment."
        },
        "x": {
          "type": "number"
        },
        "y": {
          "type": "number"
        },
        "resolution": {
          "type": "string",
          "enum": [
            "Standard",
            "High",
            "Ultra"
          ]
        }
      },
      "required": [
        "machine_id",
        "x",
        "y",
        "resolution"
      ]
    },
    "example_output": {
      "depth_mm": 2.45,
      "morphology_detail": "Embedded particulate",
      "signal_integrity": 0.99
    }
  },
  "get_material_traceability_data": {
    "description": "Retrieves material batch records, production events, and chemical analysis (e.g., contaminants) for the defect location.",
    "parameters": {
      "type": "object",
      "properties": {
        "defect_id": {
          "type": "string"
        }
      },
      "required": [
        "defect_id"
      ]
    },
    "example_output": {
      "batch_id": "BAT-9902",
      "contaminants_found": [
        "Teflon",
        "Alumina"
      ],
      "production_event_id": "PROD-EV-772"
    }
  },
  "query_maintenance_history": {
    "description": "Retrieves the calibration status and repair history for a machine.",
